@* Displays a single task card with move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex justify-content-between mt-2">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft">← Move Left</button>
            }
            else
            {
                <span></span>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="Priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="DueDate" />
        </div>
        <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm" @onclick="HandleSave" disabled="@IsSaving">
                @(IsSaving ? "Saving..." : "Save")
            </button>
            <button class="btn btn-secondary btn-sm" @onclick="OnCancel" disabled="@IsSaving">Cancel</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }
    [Parameter, EditorRequired] public string Status { get; set; } = "";

    private string Title { get; set; } = "";
    private string Assignee { get; set; } = "";
    private string Priority { get; set; } = "Medium";
    private DateTime DueDate { get; set; } = DateTime.Today.AddDays(7);
    private bool IsSaving { get; set; }

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(Title)) return;

        IsSaving = true;
        try
        {
            // Parent will call CreateTaskAsync and return the created item
            await OnTaskCreated.InvokeAsync(
                new TaskItem(0, Title.Trim(), Assignee.Trim(), Priority, DueDate, Status));
        }
        finally
        {
            IsSaving = false;
        }
    }
}

@* A single Kanban column with header, task cards, and add-task button/form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeft="() => OnMoveTask.InvokeAsync((task, MoveDirection.Left))"
                          OnMoveRight="() => OnMoveTask.InvokeAsync((task, MoveDirection.Right))" />
            }

            @if (showAddForm)
            {
                <AddTaskForm Status="@ColumnName"
                             OnTaskCreated="HandleTaskCreated"
                             OnCancel="() => showAddForm = false" />
            }
        </div>
        @if (!showAddForm)
        {
            <div class="card-footer text-center">
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showAddForm = true">
                    + Add Task
                </button>
            </div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<(TaskItem Task, MoveDirection Direction)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<TaskItem> OnAddTask { get; set; }

    private bool showAddForm;

    private async Task HandleTaskCreated(TaskItem task)
    {
        await OnAddTask.InvokeAsync(task);
        showAddForm = false;
    }

    public enum MoveDirection { Left, Right }
}

@* Search bar that filters tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await SearchTermChanged.InvokeAsync(value);
    }
}

