@* A single Kanban column with header, task cards, and add-task button/form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeft="() => OnMoveTask.InvokeAsync((task, MoveDirection.Left))"
                          OnMoveRight="() => OnMoveTask.InvokeAsync((task, MoveDirection.Right))" />
            }

            @if (showAddForm)
            {
                <AddTaskForm Status="@ColumnName"
                             OnTaskCreated="HandleTaskCreated"
                             OnCancel="() => showAddForm = false" />
            }
        </div>
        @if (!showAddForm)
        {
            <div class="card-footer text-center">
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showAddForm = true">
                    + Add Task
                </button>
            </div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<(TaskItem Task, MoveDirection Direction)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<TaskItem> OnAddTask { get; set; }

    private bool showAddForm;

    private async Task HandleTaskCreated(TaskItem task)
    {
        await OnAddTask.InvokeAsync(task);
        showAddForm = false;
    }

    public enum MoveDirection { Left, Right }
}

