arguments.file_text:
@page "/board"
@using static sv_0b3acecd492640439979a7af429d7c1f.Components.Pages.Board.KanbanColumn
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
        <p class="mt-2 text-muted">Loading tasks...</p>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Total="@allTasks.Count"
                   ToDoCount="@ToDoTasks.Count"
                   InProgressCount="@InProgressTasks.Count"
                   DoneCount="@DoneTasks.Count"
                   OverdueCount="@allTasks.Count(t => t.DueDate < DateTime.Today)" />

    <BoardSearchBar SearchTerm="@searchTerm" SearchTermChanged="HandleSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="FilteredToDoTasks"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      OnMoveTask="HandleMoveTask"
                      OnAddTask="HandleAddTask" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="FilteredInProgressTasks"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      OnMoveTask="HandleMoveTask"
                      OnAddTask="HandleAddTask" />

        <KanbanColumn ColumnName="Done"
                      Tasks="FilteredDoneTasks"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      OnMoveTask="HandleMoveTask"
                      OnAddTask="HandleAddTask" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    private static readonly string[] ColumnOrder = ["To Do", "In Progress", "Done"];

    private List<TaskItem> ToDoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> InProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> DoneTasks => allTasks.Where(t => t.Status == "Done").ToList();

    private List<TaskItem> FilteredToDoTasks => ApplyFilter(ToDoTasks);
    private List<TaskItem> FilteredInProgressTasks => ApplyFilter(InProgressTasks);
    private List<TaskItem> FilteredDoneTasks => ApplyFilter(DoneTasks);

    private List<TaskItem> ApplyFilter(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
            return tasks;
        return tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string value)
    {
        searchTerm = value;
    }

    private async Task HandleMoveTask((TaskItem Task, MoveDirection Direction) args)
    {
        var currentIndex = Array.IndexOf(ColumnOrder, args.Task.Status);
        var newIndex = args.Direction == MoveDirection.Left ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= ColumnOrder.Length) return;

        var newStatus = ColumnOrder[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.Task.Id, newStatus);
            // Update local state
            var index = allTasks.FindIndex(t => t.Id == args.Task.Id);
            if (index >= 0)
            {
                allTasks[index] = args.Task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleAddTask(TaskItem formData)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(
                formData.Title, formData.Assignee, formData.Priority, formData.DueDate);
            // CreateTaskAsync doesn't set status, so use the column's status
            allTasks.Add(created with { Status = formData.Status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

